class Solution(object):
    def countWays(self, ranges):
        MOD = 10**9 + 7
        ranges.sort()
        groups = 0
        max_end = 0
        for start, end in ranges:
            if start > max_end:
                groups += 1
            max_end = max(max_end, end)
        return pow(2, groups, MOD)
